#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int t,n,a[N],tr[N],num[N],num2[N],cntt[N],s[N];//num 前一个数字相同 num2 最后一个这个数字 
int query(int x)
{
	int sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=tr[i];
	return sum;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=(i&(-i))) tr[i]+=k;
}

int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		memset(tr,0,sizeof(tr));
		memset(num2,0,sizeof(num2));
		memset(cntt,0,sizeof(cntt));
		cin>>n;
		for(int i=1;i<=n;i++)
		{
			cin>>a[i];
			num[i]=num2[a[i]];
			num2[a[i]]=i;
		}
		int cnt=0;
		for(int i=1;i<=n;i++)
		{
			if(num[i]==0)
			{
				cnt++;
				add(i,1);
			}
			else
			{
				add(num[i],-1);
				cntt[query(i-1)-query(num[i])]++;
				add(i,1);
			}
		}
		s[n]=0;
		for(int i=n-1;i>0;i--)
		{
			s[i]=s[i+1]+cntt[i];
		}
		for(int i=1;i<=n;i++)
		{
			if(i==n) cout<<cnt<<" ";
			else cout<<s[i]+cnt<<" ";
		}
		cout<<"\n";
	}
	return 0;
}
